using System;
using System.Collections.Generic;
using System.Linq;
using System.Web.Mvc;
using System.Data.Entity;

namespace ReviewSystem.Models
{
    public class Review
    {
        public int Id { get; set; }
        public int ProductId { get; set; }
        public string UserName { get; set; }
        public string Title { get; set; }
        public string Content { get; set; }
        public int Rating { get; set; }
        public DateTime CreatedDate { get; set; }
    }

    public class Product
    {
        public int Id { get; set; }
        public string Name { get; set; }
        public string Description { get; set; }
        public decimal Price { get; set; }
    }

    public class ProductReviewViewModel
    {
        public Product Product { get; set; }
        public List<ReviewViewModel> Reviews { get; set; }
        public double AverageRating { get; set; }
        public int TotalReviews { get; set; }
    }

    public class ReviewViewModel
    {
        public int Id { get; set; }
        public string UserName { get; set; }
        public string Title { get; set; }
        public string Content { get; set; }
        public string FormattedContent { get; set; }
        public int Rating { get; set; }
        public DateTime CreatedDate { get; set; }
    }

    public class ReviewDbContext : DbContext
    {
        public DbSet<Review> Reviews { get; set; }
        public DbSet<Product> Products { get; set; }

        public ReviewDbContext() : base("DefaultConnection")
        {
        }
    }
}

namespace ReviewSystem.Helpers
{
    public static class ReviewFormatter
    {
        public static string FormatReviewContent(string content)
        {
            if (string.IsNullOrWhiteSpace(content))
                return string.Empty;

            string formatted = System.Web.HttpUtility.HtmlEncode(content);

            formatted = System.Text.RegularExpressions.Regex.Replace(
                formatted,
                @"\*\*(.+?)\*\*",
                "<strong>$1</strong>"
            );

            formatted = System.Text.RegularExpressions.Regex.Replace(
                formatted,
                @"\*(.+?)\*",
                "<em>$1</em>"
            );

            formatted = System.Text.RegularExpressions.Regex.Replace(
                formatted,
                @"__(.+?)__",
                "<strong>$1</strong>"
            );

            formatted = System.Text.RegularExpressions.Regex.Replace(
                formatted,
                @"_(.+?)_",
                "<em>$1</em>"
            );

            formatted = formatted.Replace("\r\n", "<br />").Replace("\n", "<br />");

            return formatted;
        }
    }
}

namespace ReviewSystem.Controllers
{
    public class ProductController : Controller
    {
        private readonly ReviewDbContext _context;

        public ProductController()
        {
            _context = new ReviewDbContext();
        }

        public ProductController(ReviewDbContext context)
        {
            _context = context;
        }

        public ActionResult Details(int id)
        {
            var product = _context.Products.Find(id);

            if (product == null)
            {
                return HttpNotFound();
            }

            var reviews = _context.Reviews
                .Where(r => r.ProductId == id)
                .OrderByDescending(r => r.CreatedDate)
                .ToList();

            var reviewViewModels = reviews.Select(r => new ReviewViewModel
            {
                Id = r.Id,
                UserName = r.UserName,
                Title = r.Title,
                Content = r.Content,
                FormattedContent = ReviewSystem.Helpers.ReviewFormatter.FormatReviewContent(r.Content),
                Rating = r.Rating,
                CreatedDate = r.CreatedDate
            }).ToList();

            var viewModel = new ProductReviewViewModel
            {
                Product = product,
                Reviews = reviewViewModels,
                AverageRating = reviews.Any() ? reviews.Average(r => r.Rating) : 0,
                TotalReviews = reviews.Count
            };

            return View(viewModel);
        }

        [HttpGet]
        public ActionResult SubmitReview(int productId)
        {
            var product = _context.Products.Find(productId);
            if (product == null)
            {
                return HttpNotFound();
            }

            ViewBag.ProductId = productId;
            ViewBag.ProductName = product.Name;
            return View();
        }

        [HttpPost]
        [ValidateAntiForgeryToken]
        public ActionResult SubmitReview(Review review)
        {
            if (ModelState.IsValid)
            {
                review.CreatedDate = DateTime.Now;
                _context.Reviews.Add(review);
                _context.SaveChanges();

                return RedirectToAction("Details", new { id = review.ProductId });
            }

            ViewBag.ProductId = review.ProductId;
            return View(review);
        }

        protected override void Dispose(bool disposing)
        {
            if (disposing)
            {
                _context.Dispose();
            }
            base.Dispose(disposing);
        }
    }
}